int score = 85;
// Check the score range from highest to lowest
if (score >= 90) {
    // 90 or above gets an A
    System.out.println("Grade: A");
} else if (score >= 80) {
    // 80 to 89 gets a B
    System.out.println("Grade: B");
} else if (score >= 70) {
    // 70 to 79 gets a C
    System.out.println("Grade: C");
} else {
    // Below 70 fails
    System.out.println("Grade: F");
}
// Expected output:
// Grade: B
